    }
    lines.push(forceLine);

    lines.push(`我目前面临的危机是：${userData.crisis}。`);
    lines.push(`我的初始资产为——产业：${userData.assets.产业}，金钱：${userData.assets.金钱}，粮食：${userData.assets.粮食}。`);
    if (!userData.isHistoricalFigure && userData.companion.has) {
        lines.push('\n【相伴佳人】');
        const cName = userData.companion.name || '一名女子';
        let compStr = `我身边有${cName}相伴，她正值${userData.companion.age || '芳华'}，乃是${userData.companion.identity || '寻常人家'}出身，与我算是${userData.companion.relation || '萍水相逢'}。`;
        let desc = [];
        if(userData.companion.looks.length) desc.push(`她容貌${userData.companion.looks.join('、')}`);
        if(userData.companion.temperaments.length) desc.push(`气质${userData.companion.temperaments.join('、')}`);
        if(userData.companion.talents.length) desc.push(`极具${userData.companion.talents.join('、')}之才`);
        if(userData.companion.virtues.length) desc.push(`品行${userData.companion.virtues.join('、')}`);
        if(userData.companion.custom_traits) desc.push(`此外她还${userData.companion.custom_traits}`);
        if(desc.length) lines.push(compStr + desc.join('，') + '。');
        else lines.push(compStr);

        const sexChoicesStr = Object.entries(userData.companion.sex_choices)
            .filter(([, choices]) => choices.length > 0)
            .map(([category, choices]) => `${category}方面，我偏好${choices.join('、')}`)
            .join('；');
        let finalNsfwMsg = sexChoicesStr;
        if (userData.companion.custom_nsfw) {
            finalNsfwMsg += (finalNsfwMsg ? '；' : '') + `此外我还有以下特殊偏好：${userData.companion.custom_nsfw}`;
        }
        if (finalNsfwMsg) {
            lines.push(`在房中私密事上，${finalNsfwMsg}。`);
        }
    }
    if(userData.relations || (userData.force && userData.force.dynamic) || userData.custom) {
        lines.push('\n【其他补充】');
        if(userData.relations) lines.push(`人际关系：${userData.relations}`);
        if(userData.force && userData.force.dynamic) lines.push(`势力动态：${userData.force.dynamic}`);
        if(userData.custom) lines.push(`特殊设定：${userData.custom}`);
    }
    lines.push('\n乱世的齿轮已经转动，请描述我当下面临的具体情境与抉择。');
    return lines.join('\n');
}

function displaySummary() {
    const summaryInfo = document.getElementById('summary-info');
    const displayName = userData.name_override || userData.name;
    let html = `<strong>开局年份:</strong> ${userData.situation.year}年 (${userData.situation.title})<br>`;
    if (userData.nianhao) html += `<strong>年号:</strong> ${userData.nianhao}<br>`;
    html += `<strong>姓名:</strong> ${displayName || '未定'} (<strong>表字:</strong> ${userData.zi || '无字'})<br>`;
    html += `<strong>年龄:</strong> ${userData.age || '未知'}<br>`;
    html += `<strong>出身:</strong> ${userData.faction} - ${userData.class}<br>
        <strong>声望:</strong> ${userData.reputation}<br>
        <strong>地域:</strong> ${userData.region}<br>
        <strong>职位:</strong> ${userData.position}<br>
        <strong>天赋:</strong> ${formatTalentToString(userData.talents)}<br>`;

    let forceHtml = '<strong>势力:</strong> 暂无班底<br>';
    if(userData.isHistoricalFigure && userData.force && userData.force.name) {
        forceHtml = `<strong>势力:</strong> ${userData.force.name}${userData.force.leader !== '自己' ? ` (领袖: ${userData.force.leader})` : ''}${userData.force.power ? ` (兵力: ${userData.force.power})` : ''}<br>`;
    } else if (userData.force.type && userData.force.type !== '暂无班底') {
        if (userData.force.type === '依附势力') {
            forceHtml = `<strong>势力:</strong> 依附 - ${userData.force.name} (领袖: ${userData.force.leader})<br>`;
        } else if (userData.force.type === '自立山头') {
             forceHtml = `<strong>势力:</strong> 自立 - ${userData.force.name || '未命名'}${userData.force.power ? ` (兵力: ${userData.force.power})` : ''}<br>`;
             if(userData.force.subordinates) forceHtml += `&nbsp;&nbsp;&nbsp;&nbsp;<strong>部下:</strong> ${userData.force.subordinates}<br>`;
        }
    }
    html += forceHtml;

    html += `<strong>危机:</strong> ${userData.crisis}<br>
        <strong>资产:</strong> 产业: ${userData.assets.产业}, 金钱: ${userData.assets.金钱}, 粮食: ${userData.assets.粮食}<br>`;

    if (userData.isHistoricalFigure && userData.children) {
        html += `<strong>子嗣:</strong> ${userData.children}<br>`;
    } else if (!userData.isHistoricalFigure && userData.children.has && userData.children.info) {
        html += `<strong>子嗣:</strong> ${userData.children.info}<br>`;
    }

    if (!userData.isHistoricalFigure && userData.companion.has) {
        html += `<strong>相伴佳人:</strong>`;
        if (userData.companion.name) html += ` 姓名: ${userData.companion.name}`;
        if (userData.companion.age) html += `, 年龄: ${userData.companion.age}`;
        if (userData.companion.identity) html += `, 身份: ${userData.companion.identity}`;
        if (userData.companion.relation) html += `, 关系: ${userData.companion.relation}`;
        html += `<br>&nbsp;&nbsp;&nbsp;&nbsp;<strong>特征:</strong> `;
        const features = [
            ...userData.companion.looks,
            ...userData.companion.temperaments,
            ...userData.companion.talents,
            ...userData.companion.virtues,
        ];
        html += features.join('、') || '无';
        if (userData.companion.custom_traits) html += `<br>&nbsp;&nbsp;&nbsp;&nbsp;<strong>补充特质:</strong> ${userData.companion.custom_traits}`;
        html += `<br>`;

        const sexChoicesStr = Object.entries(userData.companion.sex_choices)
            .filter(([, choices]) => choices.length > 0)
            .map(([category, choices]) => `<strong>${category}:</strong> ${choices.join('、')}`)
            .join('<br>&nbsp;&nbsp;&nbsp;&nbsp;');
        let finalNsfwHtml = sexChoicesStr;
        if (userData.companion.custom_nsfw) {
             finalNsfwHtml += (finalNsfwHtml ? '<br>&nbsp;&nbsp;&nbsp;&nbsp;' : '') + `<strong>特殊偏好:</strong> ${userData.companion.custom_nsfw}`;
        }
        if (finalNsfwHtml) {
            html += `<strong>房中私密:</strong><br>&nbsp;&nbsp;&nbsp;&nbsp;${finalNsfwHtml}<br>`;
        }
    }
    summaryInfo.innerHTML = html;
    document.getElementById('summary-inputs').style.display = 'flex';
}

// 统一编辑功能
function openEditModal() {
    const container = document.getElementById('edit-form-container');
    container.innerHTML = '';

    const fieldsToEdit = [
        { id: 'edit-nianhao', label: '年号', value: userData.nianhao || '' },
        { id: 'edit-name', label: '姓名', value: userData.name_override || userData.name || '' },
        { id: 'edit-zi', label: '表字', value: userData.zi || '' },
        { id: 'edit-age', label: '年龄', value: userData.age || '' },
        { id: 'edit-position', label: '职位/地位', value: userData.position || '' },
        { id: 'edit-reputation', label: '声望', value: userData.reputation || '' },
        { id: 'edit-region', label: '地域', value: userData.region || '' },
        { id: 'edit-crisis', label: '当前危机', value: userData.crisis || '', isTextarea: true },
        { id: 'edit-assets-industry', label: '产业', value: userData.assets.产业 || '', isTextarea: true },
        { id: 'edit-assets-gold', label: '金钱', value: userData.assets.金钱 || '' },
        { id: 'edit-assets-food', label: '粮食', value: userData.assets.粮食 || '' }
    ];

    if (userData.isHistoricalFigure && userData.children) {
        fieldsToEdit.push({ id: 'edit-children', label: '子嗣', value: userData.children, isTextarea: true });
    } else if (!userData.isHistoricalFigure && userData.children.has) {
        fieldsToEdit.push({ id: 'edit-children-info', label: '子嗣', value: userData.children.info || '', isTextarea: true });
    }

    if (userData.isHistoricalFigure && userData.force && userData.force.name) {
         let fStr = `${userData.force.name}${userData.force.leader !== '自己' ? ` (领袖: ${userData.force.leader})` : ''}${userData.force.power ? ` (兵力: ${userData.force.power})` : ''}`;
         fieldsToEdit.push({ id: 'edit-force-str', label: '势力信息', value: fStr, isTextarea: true });
    } else if (userData.force.type && userData.force.type !== '暂无班底') {
         if (userData.force.type === '依附势力') {
             let fStr = `依附 - ${userData.force.name} (领袖: ${userData.force.leader})`;
             fieldsToEdit.push({ id: 'edit-force-str', label: '势力信息', value: fStr, isTextarea: true });
         } else if (userData.force.type === '自立山头') {
             fieldsToEdit.push({ id: 'edit-force-name', label: '势力名称', value: userData.force.name || '' });
             fieldsToEdit.push({ id: 'edit-force-power', label: '势力兵力', value: userData.force.power || '' });
             fieldsToEdit.push({ id: 'edit-force-sub', label: '势力部下', value: userData.force.subordinates || '', isTextarea: true });
         }
    }

    if (!userData.isHistoricalFigure && userData.companion.has) {
         fieldsToEdit.push({ id: 'edit-comp-name', label: '佳人姓名', value: userData.companion.name || '' });
         fieldsToEdit.push({ id: 'edit-comp-traits', label: '佳人补充特质', value: userData.companion.custom_traits || '', isTextarea: true });
         fieldsToEdit.push({ id: 'edit-comp-nsfw', label: '私密特殊偏好', value: userData.companion.custom_nsfw || '', isTextarea: true });
    }

    fieldsToEdit.forEach(field => {
        const group = document.createElement('div');
        group.className = 'edit-form-group';
        const label = document.createElement('label');
        label.className = 'edit-form-label';
        label.textContent = field.label;

        let input;
        if (field.isTextarea) {
            input = document.createElement('textarea');
            input.className = 'modal-textarea';
            input.style.minHeight = '60px';
        } else {
            input = document.createElement('input');
            input.type = 'text';
            input.className = 'edit-form-input';
        }
        input.id = field.id;
        input.value = field.value;

        group.appendChild(label);
        group.appendChild(input);
        container.appendChild(group);
    });

    document.getElementById('edit-modal').classList.add('show');
}

function closeEditModal() {
    document.getElementById('edit-modal').classList.remove('show');
}

function saveEditedData() {
    userData.nianhao = document.getElementById('edit-nianhao')?.value.trim() || '';

    // 处理姓名，为了不影响后续逻辑，这里用name_override存自定义名
    const newName = document.getElementById('edit-name')?.value.trim() || '';
    if(userData.isHistoricalFigure) {
        userData.name_override = newName;
    } else {
        userData.name = newName;
    }

    userData.zi = document.getElementById('edit-zi')?.value.trim() || '';
    userData.age = document.getElementById('edit-age')?.value.trim() || '';
    userData.position = document.getElementById('edit-position')?.value.trim() || '';
    userData.reputation = document.getElementById('edit-reputation')?.value.trim() || '';
    userData.region = document.getElementById('edit-region')?.value.trim() || '';
    userData.crisis = document.getElementById('edit-crisis')?.value.trim() || '';

    userData.assets.产业 = document.getElementById('edit-assets-industry')?.value.trim() || '';
    userData.assets.金钱 = document.getElementById('edit-assets-gold')?.value.trim() || '';
    userData.assets.粮食 = document.getElementById('edit-assets-food')?.value.trim() || '';

    if (document.getElementById('edit-children')) {
        userData.children = document.getElementById('edit-children').value.trim();
    }
    if (document.getElementById('edit-children-info')) {
        userData.children.info = document.getElementById('edit-children-info').value.trim();
    }

    if (document.getElementById('edit-force-str')) {
        // 粗略处理历史人物和依附势力的整体修改
        userData.force.name = document.getElementById('edit-force-str').value.trim();
    }
    if (document.getElementById('edit-force-name')) userData.force.name = document.getElementById('edit-force-name').value.trim();
    if (document.getElementById('edit-force-power')) userData.force.power = document.getElementById('edit-force-power').value.trim();
    if (document.getElementById('edit-force-sub')) userData.force.subordinates = document.getElementById('edit-force-sub').value.trim();

    if (document.getElementById('edit-comp-name')) userData.companion.name = document.getElementById('edit-comp-name').value.trim();
    if (document.getElementById('edit-comp-traits')) userData.companion.custom_traits = document.getElementById('edit-comp-traits').value.trim();
    if (document.getElementById('edit-comp-nsfw')) userData.companion.custom_nsfw = document.getElementById('edit-comp-nsfw').value.trim();

    closeEditModal();
    displaySummary();
}

function onConfirm() {
    userData.family_info = document.getElementById('input-family-info').value;
    userData.relations = document.getElementById('input-relations').value;
    if(userData.force) userData.force.dynamic = document.getElementById('input-force-dynamic').value;
    userData.custom = document.getElementById('input-custom').value;

    try {
        const charWB = getCharWorldbookNames('current');
        const wbName = charWB.primary;
        if (!wbName) {
            alert('当前角色卡未绑定主世界书，无法写入用户信息条目。\n请先为角色卡绑定一本世界书。');
            return;
        }
        deleteWorldbookEntries(wbName, (entry) => entry.name === '用户信息').then(() => {
            return createWorldbookEntries(wbName, [{
                name: '用户信息',
                enabled: true,
                strategy: { type: 'constant' },
                position: { type: 'before_character_definition' },
                content: formatUserDataAsContent(),
            }]);
        }).then(() => {
            return createChatMessages([{ role: 'user', message: formatUserDataAsMessage() }]);
        }).then(() => {
            return triggerSlash('/send');
        }).catch((err) => {
            alert('操作失败: ' + (err.message || String(err)));
            console.error('[角色创建] onConfirm error:', err);
        });
    } catch(e) {
        console.log('Final User Data:', formatUserDataAsMessage());
        alert('API调用失败，请确认在正确的环境中运行。\n' + e.message + '\n\n角色设定已输出至控制台。');
    }
}

function showPreviewModal() {
