  <script type="module">
    // 改进后的 formatNumber 函数，保留原始字符串中的非数字字符（如单位）
    function formatNumberWithUnit(str) {
      if (!str && str !== 0) return '0';
      const s = String(str);
      // 提取数字部分和非数字部分
      const match = s.match(/^(-?\d+)(.*)$/);
      if (match) {
        const numPart = parseInt(match[1], 10).toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
        const unitPart = match[2] || '';
        return numPart + unitPart;
      }
      return s; // 如果没有匹配到开头的数字，直接返回原字符串
    }

    // 原有的 formatNumber 仅用于纯数字格式化（如兵力）
    function formatNumber(num) {
      const parsed = parseInt(num, 10);
      if (isNaN(parsed)) return '0';
      return parsed.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    }

    function getStatusClass(value, good = 50, warn = 0) {
      const num = parseInt(value, 10) || 0;
      if (num >= good) return 'badge-good';
      if (num >= warn) return 'badge-warning';
      return 'badge-danger';
    }

    function getSafeStatData() {
      let sd = {};
      try {
        const rawVars = getAllVariables() || {};
        sd = rawVars.stat_data;
        if (typeof sd === 'string') {
          sd = JSON.parse(sd);
        } else if (sd !== null && typeof sd === 'object') {
          sd = JSON.parse(JSON.stringify(sd));
        }
      } catch (e) {
        console.warn('解析 stat_data 失败, 尝试跳过:', e);
      }
      return sd || {};
    }

