    function showModal(title, contentHtml) {
      $('#modal-title').text(title);
      $('#modal-body-content').html(contentHtml);
      $('#modal-overlay').fadeIn(200);
    }

    function buildTagsHtml(label, items) {
      let arr = [];
      if (Array.isArray(items)) {
        arr = items;
      } else if (typeof items === 'string') {
        arr = items.split(/[,，、|｜\s]+/).filter(Boolean);
      } else if (typeof items === 'object' && items !== null) {
        arr = Object.values(items).filter(Boolean);
      }

      if (arr.length === 0) return '';
      const tags = arr.map(item => `<div class="tag tag-small">${item}</div>`).join('');
      return `<div class="stat-label" style="margin-top:6px;">${label}</div><div class="tag-container">${tags}</div>`;
    }

    function buildKeyValueHtml(label, dataObject) {
        if (!dataObject || typeof dataObject !== 'object' || Object.keys(dataObject).length === 0) {
            return `<div class="stat-label" style="margin-top:6px;">${label}</div><div class="dynamic-text empty-text">暂无记载</div>`;
        }
        const items = Object.entries(dataObject)
            .filter(([_, value]) => value !== null && value !== undefined && value !== '')
            .map(([key, value]) => `<div><span style="color:var(--ink-secondary);">${key}：</span>${value}</div>`)
            .join('');
        if (!items) return `<div class="stat-label" style="margin-top:6px;">${label}</div><div class="dynamic-text empty-text">暂无记载</div>`;
        return `<div class="stat-label" style="margin-top:6px;">${label}</div><div class="dynamic-text">${items}</div>`;
    }

    async function init() {
      await waitGlobalInitialized('Mvu');
      populateCharacterData();

      const triggerUpdate = () => setTimeout(populateCharacterData, 100);
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, triggerUpdate);

      if (typeof window.eventSource !== 'undefined') {
          window.eventSource.on('variablesUpdated', triggerUpdate);
      }

      $('.panel-header').off('click').on('click', function() {
        $(this).toggleClass('collapsed').next('.panel-content').slideToggle(200);
      });

      $('.scroll-container').on('click', '.toggle-subcamps', function(e) {
        e.stopPropagation();
        const container = $(this).closest('.troop-group').find('.subcamps-container');
        container.slideToggle(200);
        const text = $(this).text();
        if (text === '▼') {
          $(this).text('▲');
        } else {
          $(this).text('▼');
        }
      });

      $('.scroll-container').on('click', '.clickable', function() {
        const sd = getSafeStatData();
        const type = $(this).data('type');
        const name = $(this).data('name');
        let data, title, contentHtml = '';

        if (type === 'companion') {
            data = _.get(sd, ['佳人', '后宫', name]);
            if (!data) return;
            title = `佳人·${name}`;

            const relation = data.与玩家关系 || data.关系 || data.与你关系 || _.get(data, '基本设定.与玩家关系') || '暂无记载';
            const ageGroup = data.年龄段 || data.年龄 || _.get(data, '基本设定.年龄段') || '暂无记载';
            const identity = data.身份 || _.get(data, '基本设定.身份') || '暂无记载';

            const rongmao = data.容貌 || _.get(data, '特质描述.容貌') || [];
            const qizhi = data.气质 || _.get(data, '特质描述.气质') || [];
            const caiqing = data.才情 || _.get(data, '特质描述.才情') || [];
            const pinde = data.品德 || _.get(data, '特质描述.品德') || [];

            const tagsHtml = [
              buildTagsHtml('容貌', rongmao),
              buildTagsHtml('气质', qizhi),
              buildTagsHtml('才情', caiqing),
              buildTagsHtml('品德', pinde)
            ].filter(Boolean).join('');

            const featureContent = tagsHtml || '<div class="dynamic-text empty-text">暂未展露明显特质</div>';

            const privateClothes = data.私密衣着 || _.get(data, '私密设定.私密衣着') || {};
            const playHabits = data.癖好玩法 || _.get(data, '私密设定.癖好玩法') || {};
            const sexFeatures = data.性特征 || _.get(data, '私密设定.性特征') || {};

            const sexStats = data.性事 || _.get(data, '性事统计.性事') || {};
            const sexHtml = Object.entries(sexStats)
              .filter(([_, value]) => value !== null && value !== undefined)
              .map(([key, value]) => `<div><span style="color:var(--ink-secondary);">${key}：</span>${value}次</div>`)
              .join('');

            const portraitUrl = CHARACTER_PORTRAITS[name] || '';
            const portraitHtml = portraitUrl
              ? `<div class="modal-portrait-single"><img src="${portraitUrl}" alt="${name}"></div>`
              : ``;

            contentHtml = `
              ${portraitHtml}
              <div class="modal-section">
                <div class="modal-section-title">基本信息</div>
                <div class="modal-info-line"><strong>身份：</strong>${identity}</div>
                <div class="modal-info-line"><strong>年龄段：</strong>${ageGroup}</div>
                <div class="modal-info-line"><strong>与你关系：</strong>${relation}</div>
              </div>
              <div class="modal-section">
                <div class="modal-section-title">性情特质</div>
                ${featureContent}
              </div>
              <div class="modal-section">
                <div class="modal-section-title">闺房秘事</div>
                ${buildKeyValueHtml('性特征', sexFeatures)}
                ${buildKeyValueHtml('私密衣着', privateClothes)}
                ${buildKeyValueHtml('癖好玩法', playHabits)}
              </div>
              <div class="modal-section">
                <div class="modal-section-title">欢好记</div>
                <div class="dynamic-text">${sexHtml || '<span class="empty-text">尚无记录</span>'}</div>
              </div>
            `;
        } else if (type === 'estate') {
            data = _.get(sd, ['玩家', '个人处境', '产业', name]);
            if (!data) return;
            title = `产业·${name}`;
            contentHtml = `
              <div class="modal-section">
                <div class="modal-info-line"><strong>收入：</strong>${data.收入 || '无'}</div>
                <div class="modal-info-line"><strong>支出：</strong>${data.支出 || '无'}</div>
              </div>
              <div class="modal-section">
                <div class="modal-section-title">产业说明</div>
                <div class="dynamic-text">${data.说明 || '<span class="empty-text">暂无说明</span>'}</div>
              </div>
            `;
        } else if (type === 'subordinate') {
            data = _.get(sd, ['玩家', '势力信息', '部下', name]);
            if (!data) return;
            title = `部下·${name}`;
            contentHtml = `
              <div class="modal-section">
                <div class="modal-info-line"><strong>官职：</strong>${data.官职 || '无'}</div>
                <div class="modal-info-line"><strong>好感：</strong>${data.好感 || 50}</div>
              </div>
              <div class="modal-section">
                <div class="modal-section-title">评价</div>
                <div class="dynamic-text">${data.评价 || '<span class="empty-text">暂无评价</span>'}</div>
              </div>
            `;
        } else if (type === 'family-member') {
            data = _.get(sd, ['玩家', '社会信息', '门第', '家族成员', name]);
            if (!data) return;
            title = `宗族·${name}`;
            contentHtml = `
              <div class="modal-section">
                <div class="modal-info-line"><strong>表字：</strong>${data.表字 || '无'}</div>
                <div class="modal-info-line"><strong>年龄：</strong>${data.年龄 || 0}岁</div>
                <div class="modal-info-line"><strong>关系：</strong>${data.关系 || '未知'}</div>
                <div class="modal-info-line"><strong>官职：</strong>${data.官职 || '白身'}</div>
              </div>
            `;
        } else if (type === 'offspring') {
            data = _.get(sd, ['玩家', '子嗣', '成员', name]);
            if (!data) return;
            title = `子嗣·${name}`;
            contentHtml = `
              <div class="modal-section">
                <div class="modal-info-line"><strong>年龄：</strong>${data.年龄 || 0}岁</div>
                <div class="modal-info-line"><strong>身份：</strong>${data.身份 || '无'}</div>
                <div class="modal-info-line"><strong>好感：</strong>${data.好感 || 50}</div>
              </div>
              <div class="modal-section">
                <div class="modal-section-title">评价</div>
                <div class="dynamic-text">${data.评价 || '<span class="empty-text">暂无评价</span>'}</div>
              </div>
            `;
        } else if (type === 'troop') {
            const isSub = String($(this).data('issub')) === 'true';
            const parentName = $(this).data('parent');

            if (isSub) {
               data = _.get(sd, ['玩家', '势力信息', '部队', parentName, '下辖小营', name]);
               title = `小营·${name}`;
