               data = _.get(sd, ['玩家', '势力信息', '部队', name]);
               title = `${data.类型 || '部队'}·${name}`;
            }

            if (!data) return;

            const loyalty = data.忠诚 || '忠诚';
            const commanderLabel = (data.类型 === '大营' && !isSub) ? '统帅' : '统领';
            const commanderName = (data.类型 === '大营' && !isSub) ? (data.统帅 || '未任命') : (data.统领 || '未任命');

