               contentHtml += `
                 <div class="modal-section">
                   <div class="modal-section-title">下辖小营</div>
                   <div class="list" style="border: 1px solid var(--border-antique); border-radius: 4px; padding: 4px;">
               `;
               for (const [subName, subData] of Object.entries(data.下辖小营)) {
