                   else if (subLoyalty === '叛乱') subLoyaltyClass = 'loyalty-rebel';
                   const subMoraleClass = subData.士气 === '高昂' ? 'badge-good' : (subData.士气 === '低落' ? 'badge-danger' : 'badge-warning');
