                   const modalSubBingzhongTag = subData.兵种 ? `<span class="loyalty-box" style="background:#f5f0e6;color:#5a5343;border-color:#d7c9b0;margin-right:4px;padding:1px 4px;font-size:10px;white-space:nowrap;flex-shrink:0;">${subData.兵种}</span>` : '';

