<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <title>军事沙盘</title>
    <style>
        /* 引入外部字体 */
        @font-face {
            font-family: 'Maobi';
            src: url('https://testingcf.jsdelivr.net/gh/css-go/Maobi/Maobi.woff2') format('woff2');
        }

        * {
