<body>
    <div class="deduction-container" id="main-content">
        <div class="loading">正在展开沙盘，分析军情...</div>
    </div>

    <script>
        /* ========== 获取消息内容 ========== */
        function getMessageData() {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (!chatMessages || chatMessages.length === 0) {
                return ""; /* 获取不到时返回空字符串，交由解析引擎提供默认值 */
            }
            return chatMessages[0].message;
        }

        /* ========== 解析数据的容错引擎 ========== */
        function parseData(messageText) {
            /* 提供默认的待命结构 */
            var data = {
                type: '沙盘推演',
                description: '战局未明，请将军下达军令。',
                options: {
                    A: { text: '顺应战局之必然结果。', minds: [], locked: false },
                    B: { text: '副将暂无其他建言。', minds: [], locked: true },
                    C: { text: '尚未触发破局奇效。', minds: [], locked: true },
                    D: { text: '局势稳定，未生变数。', minds: [], locked: true }
                }
            };

            if (!messageText) return data;

            /* 宽容正则，匹配标签内容 */
            var match = messageText.match(/<military_deduction>([\s\S]*?)(?:<\/military_deduction>|$)/);
            if (!match || !match[1]) return data;

            var content = match[1];
            var lines = content.trim().split('\n').filter(line => line.trim() !== '');

            lines.forEach(line => {
                var kvMatch = line.match(/\[([^|]+)\|([\s\S]+)\]/);
                if (!kvMatch) return;

                var key = kvMatch[1].trim();
                var value = kvMatch[2].trim();

                try {
                    switch(key) {
                        case '类型': data.type = value; break;
                        case '描述': data.description = value; break;
                        case '选项A': data.options.A.text = value; break;
                        case 'A心里话': data.options.A.minds = value.split('|').map(s => s.trim()).filter(s => s !== ''); break;
                        case '选项B': data.options.B.text = value; break;
                        case 'B心里话': data.options.B.minds = value.split('|').map(s => s.trim()).filter(s => s !== ''); break;
                        case 'B锁定': data.options.B.locked = (value === '有'); break;
                        case '选项C': data.options.C.text = value; break;
                        case 'C心里话': data.options.C.minds = value.split('|').map(s => s.trim()).filter(s => s !== ''); break;
                        case 'C锁定': data.options.C.locked = (value === '有'); break;
                        case '选项D': data.options.D.text = value; break;
                        case 'D心里话': data.options.D.minds = value.split('|').map(s => s.trim()).filter(s => s !== ''); break;
                        case 'D锁定': data.options.D.locked = (value === '有'); break;
                    }
                } catch (e) {
                    console.warn("单行解析出错，已忽略:", line, e);
                }
            });

            /* 强制解锁逻辑：如果内容不是默认文本，说明有实际数据，强制解锁 */
            if (data.options.B.text !== '副将暂无其他建言。' && data.options.B.locked === undefined) data.options.B.locked = false;
            if (data.options.C.text !== '尚未触发破局奇效。' && data.options.C.locked === undefined) data.options.C.locked = false;
            if (data.options.D.text !== '局势稳定，未生变数。' && data.options.D.locked === undefined) data.options.D.locked = false;

            return data;
        }

        /* ========== 渲染界面 ========== */
        function renderPage(data) {
            var optionsHtml = '';
            ['A', 'B', 'C', 'D'].forEach(key => {
                var option = data.options[key];
                if (!option) return;

                var title = '';
                if(key === 'A') title = '客观推演';
                if(key === 'B') title = '副将建言';
                if(key === 'C') title = '天赋之策';
                if(key === 'D') title = '名望变数';

                var mindsHtml = (option.minds || []).map(mind => {
                    var parts = mind.split('：');
                    var role = parts.length > 1 ? `<span class="role">${parts[0]}：</span>` : '';
                    var thought = parts.length > 1 ? parts.slice(1).join('：') : mind;
                    return `<div class="mind-talk-item">${role}${thought}</div>`;
                }).join('');

                optionsHtml += `
                    <div class="option-card ${option.locked ? 'locked' : ''}" ${!option.locked ? `onclick="handleClick('推演选择', '${key}')"` : ''}>
                        <div class="option-header">
                            <span class="option-label">${key}</span>
                            <div class="option-title">${title}</div>
                            ${option.locked ? '<span class="locked-icon">🔒</span>' : ''}
                        </div>
                        <div class="option-content" style="padding: 15px; border-bottom: 1px dashed #4a4130;">
                            ${option.text || '无'}
                        </div>
                        <div class="mind-talk-section">
                            ${mindsHtml || '<div class="mind-talk-item" style="color:#999; font-style:italic;">（暂无人议论...）</div>'}
                        </div>
                    </div>
                `;
            });

            var mainHtml = `
                <div class="title-bar">${data.type || '军事沙盘'}</div>
                <div class="description-box">${data.description}</div>
                <div class="options-grid">${optionsHtml}</div>
            `;

            document.getElementById('main-content').innerHTML = mainHtml;
        }

        /* ========== 交互函数 ========== */
        function handleClick(keyword, param) {
            if (typeof triggerSlash === 'function') {
                triggerSlash('/send ' + keyword + '：' + param + '|/trigger');
            } else {
                console.error("执行命令失败");
            }
        }

        /* ========== 主函数 ========== */
        function init() {
            try {
                var messageText = getMessageData();
                var data = parseData(messageText);
                renderPage(data);
            } catch (error) {
                console.error("军事沙盘渲染错误:", error);
                document.getElementById('main-content').innerHTML = '<div class="loading">推演沙盘受损，未能清晰呈现军情。请重试...</div>';
            }
        }

        $(function() { init(); });
    </script>
</body>
</html>
