<body>
    <div class="court-deduction-wrapper" id="render-target">
        <div class="fallback-msg">正在整理卷宗，推演局势...</div>
    </div>

    <script>
        /* 获取消息内容 */
        function fetchRawMessage() {
            var msgs = getChatMessages(getCurrentMessageId());
            if (!msgs || msgs.length === 0) return null;
            return msgs[0].message;
        }

        /* 解析数据的容错引擎 */
        function parseDiplomacyData(rawText) {
            /* 提供默认结构，防止后续访问报错 */
            var parsed = {
                type: '局势推演',
                desc: '局势混沌，尚待明察。',
                opts: {
                    A: { title: '客观推断', text: '顺应局势之必然结果。', minds: [], locked: false },
                    B: { title: '群臣建言', text: '暂无同僚或副使提出异议。', minds: [], locked: true },
                    C: { title: '破局之策', text: '自身才干尚不足以引发奇效。', minds: [], locked: true },
                    D: { title: '隐秘行动', text: '暗中布局，伺机而动。', minds: [], locked: true } /* 新增D选项默认结构 */
                }
            };

            if (!rawText) return parsed;

            /* 宽容正则，即使没有闭合标签也能抓取到内容 */
            var match = rawText.match(/<diplomacy_deduction>([\s\S]*?)(?:<\/diplomacy_deduction>|$)/);
            if (!match || !match[1]) return parsed; /* 如果完全没匹配到，返回默认结构 */

            var blockContent = match[1];
            var lines = blockContent.split('\n');

            lines.forEach(function(line) {
                var kvMatch = line.match(/\[([^|]+)\|([\s\S]+)\]/);
                if (!kvMatch) return;

                var key = kvMatch[1].trim();
                var val = kvMatch[2].trim();

                try {
                    if (key === '类型' && val) parsed.type = val;
                    if (key === '描述' && val) parsed.desc = val;

                    if (key === '选项A' && val) parsed.opts.A.text = val;
                    if (key === 'A心里话' && val) parsed.opts.A.minds = val.split('|').map(s => s.trim()).filter(s => s !== '');

                    if (key === '选项B' && val) parsed.opts.B.text = val;
                    if (key === 'B心里话' && val) parsed.opts.B.minds = val.split('|').map(s => s.trim()).filter(s => s !== '');
                    if (key === 'B锁定') parsed.opts.B.locked = (val === '有');
                    if (val && key === '选项B' && val !== '暂无同僚或副使提出异议。') parsed.opts.B.locked = false;

                    if (key === '选项C' && val) parsed.opts.C.text = val;
                    if (key === 'C心里话' && val) parsed.opts.C.minds = val.split('|').map(s => s.trim()).filter(s => s !== '');
                    if (key === 'C锁定') parsed.opts.C.locked = (val === '有');
                    if (val && key === '选项C' && val !== '自身才干尚不足以引发奇效。') parsed.opts.C.locked = false;

                    /* 新增D选项解析逻辑 */
                    if (key === '选项D' && val) parsed.opts.D.text = val;
                    if (key === 'D心里话' && val) parsed.opts.D.minds = val.split('|').map(s => s.trim()).filter(s => s !== '');
                    if (key === 'D锁定') parsed.opts.D.locked = (val === '有');
                    if (val && key === '选项D' && val !== '暗中布局，伺机而动。') parsed.opts.D.locked = false;

                } catch (e) {
                    console.warn("单行解析出错，已忽略:", line, e);
                }
            });

            return parsed;
        }

        /* 渲染界面 */
        function buildInterface(data) {
            var target = document.getElementById('render-target');
            var cardsHtml = '';
            var optKeys = ['A', 'B', 'C', 'D']; /* 增加D选项到渲染队列 */

            optKeys.forEach(function(k) {
                var opt = data.opts[k];
                var lockedClass = opt.locked ? 'is-locked' : '';
                var clickEvent = opt.locked ? '' : 'onclick="submitChoice(\'' + k + '\')"';

                var mindLinesHtml;
                if (opt.minds && opt.minds.length > 0) {
                     mindLinesHtml = opt.minds.map(function(m) {
                        var parts = m.split('：');
                        if (parts.length > 1) {
                            return '<div class="mind-line"><span class="mind-role">' + parts[0] + '</span><span class="mind-text">' + parts.slice(1).join('：') + '</span></div>';
                        } else {
                            return '<div class="mind-line"><span class="mind-text">' + m + '</span></div>';
                        }
                    }).join('');
                } else {
                    /* 如果没有心里话，就显示提示文字 */
                    mindLinesHtml = '<div class="mind-line mind-fallback">（暂无人议论...）</div>';
                }
                var mindsHtml = '<div class="minds-area">' + mindLinesHtml + '</div>';

                cardsHtml += `
                    <div class="strategy-card ${lockedClass}" ${clickEvent}>
                        <div class="card-top">
                            <span class="opt-letter">${k}</span>
                            <span class="opt-name">${opt.title}</span>
                        </div>
                        <div class="card-body">
                            ${opt.text}
                        </div>
                        ${mindsHtml}
                    </div>
                `;
            });

            /* 组装主框架 */
            target.innerHTML = `
                <div class="title-header">
                    <div class="title-text">纵横捭阖</div>
                    <div class="badge-type">${data.type}</div>
                </div>
                <div class="situation-desc">
                    ${data.desc}
                </div>
                <div class="strategies-grid">
                    ${cardsHtml}
                </div>
            `;
        }

        /* 交互逻辑 */
        function submitChoice(choiceLetter) {
            if (typeof triggerSlash === 'function') {
                triggerSlash('/send 我选择对策：' + choiceLetter + '|/trigger');
            } else {
                console.error("执行命令失败");
            }
        }

        /* 启动 */
        $(function() {
            try {
                var rawText = fetchRawMessage();
                var data = parseDiplomacyData(rawText);
                buildInterface(data);
            } catch (err) {
                document.getElementById('render-target').innerHTML = '<div class="fallback-msg">推演卷宗受损，未能清晰呈现局势。请让秋青子重试...</div>';
                console.error("纵横捭阖渲染异常:", err);
            }
        });
    </script>
</body>
</html>
