    const factionEras = eraMap[faction];
    if (!factionEras) return '';

    for (let i = 0; i < factionEras.length; i++) {
        const era = factionEras[i];
        if (year >= era.start && year <= era.end) {
            let yearNum = year - era.start + 1;
            let yearStr = yearNum === 1 ? '元' : yearNum.toString();
            // 处理包含斜杠的混合年号（简单取第一个）
            let eraName = era.name.split('/')[0];
            return `${eraName}${yearStr}年`;
        }
    }
    return '';
}


