function getClassListForFaction(faction, year) {
    const factionForces = worldData.classBasedForces[faction]?.[year];
    let classes = [];
    if (factionForces) {
        classes = Object.keys(factionForces).map(className => {
            const details = defaultClassDetails[className] || { desc: '平民百姓', position: '普通成员', assets: { 产业: '一般，收入10(石)，支出5(石)', 金钱: '10(金)', 粮食: '10(石)' } };
            return {
                name: className,
                desc: details.desc,
                position: details.position,
                assets: details.assets,
                crises: getClassCrisesForYear(year, faction, className)
            };
        });
    } else {
        classes = [{
            name: '流民',
            desc: '无根无萍，朝不保夕',
            position: '平民',
            assets: { 产业: '无，收入0(石)，支出0(石)', 金钱: '0(金)', 粮食: '0(石)' },
            crises: [{name: '饿死街头', desc: ''}]
        }];
    }
    return classes;
}

let userData = {};
let currentPage = 0;
const totalPages = 14;

function resetUserData() {
