    renderCards('force-choice-cards', choices, 'force-choice-cards', item => {
        userData.force.type = item.name;
        document.getElementById('force-details-depend').style.display = item.name === '依附势力' ? 'flex' : 'none';
        document.getElementById('force-details-create').style.display = item.name === '自立山头' ? 'flex' : 'none';
