function formatTalentToString(talents) {
    if (!talents || Object.keys(talents).length === 0) return '平庸之辈';
    const activeTalents = [];
    for (const [key, value] of Object.entries(talents)) {
        if (value !== 0) {
            const title = getTalentTitle(key, value);
            activeTalents.push(`${key}${value > 0 ? '+' : ''}${value}(${title})`);
        }
    }
    return activeTalents.length > 0 ? activeTalents.join('，') : '平庸之辈';
}

function formatUserDataAsContent() {
    let lines = [];
    const displayName = userData.name_override || userData.name;
    const eraNameStr = getEraName(userData.situation.year, userData.faction);
    const yearDisplay = eraNameStr ? `${userData.situation.year}年 (${eraNameStr})` : `${userData.situation.year}年`;

    lines.push('[用户角色信息]');
    lines.push(`天下大势: ${yearDisplay} - ${userData.situation.title}`);
    lines.push(`姓名: ${displayName || '未定'}`);
    if(userData.zi) lines.push(`表字: ${userData.zi}`);
    if(userData.age) lines.push(`年龄: ${userData.age}`);
    lines.push(`所属阵营: ${userData.faction}`);
    lines.push(`所在地域: ${userData.region}`);
    lines.push(`出身家世: ${userData.class}`);
    lines.push(`初始声望: ${userData.reputation}`);
    lines.push(`官职/地位: ${userData.position}`);
    lines.push(`天赋异禀: ${formatTalentToString(userData.talents)}`);

    let forceText = '暂无班底';
    if(userData.isHistoricalFigure && userData.force) {
        if(userData.force.name) forceText = userData.force.name;
        if(userData.force.leader && userData.force.leader !== '自己') forceText += ` (领袖: ${userData.force.leader})`;
        if(userData.force.power) forceText += ` (兵力: ${userData.force.power})`;
    } else if (userData.force.type && userData.force.type !== '暂无班底') {
        if (userData.force.type === '依附势力') {
            forceText = `${userData.force.name} (领袖: ${userData.force.leader})`;
        } else if (userData.force.type === '自立山头') {
            forceText = `${userData.force.name || '未命名'}${userData.force.power ? ` (兵力: ${userData.force.power})` : ''}`;
            if(userData.force.subordinates) lines.push(`核心部下: ${userData.force.subordinates}`);
        }
    }
    lines.push(`势力归属: ${forceText}`);

    lines.push(`当前危机: ${userData.crisis}`);
    lines.push(`初始资产: 产业(${userData.assets.产业}), 金钱(${userData.assets.金钱}), 粮食(${userData.assets.粮食})`);

    if (userData.family_info) {
        lines.push(`家族情况: ${userData.family_info}`);
    }

    if (userData.isHistoricalFigure && userData.children) {
        lines.push(`已知子嗣: ${userData.children}`);
    } else if (!userData.isHistoricalFigure && userData.children.has && userData.children.info) {
        lines.push(`已有子嗣: ${userData.children.info}`);
    }

    if (!userData.isHistoricalFigure && userData.companion.has) {
        let compStr = [];
        if (userData.companion.name) compStr.push(`姓名: ${userData.companion.name}`);
        if (userData.companion.age) compStr.push(`年龄: ${userData.companion.age}`);
        if (userData.companion.identity) compStr.push(`身份: ${userData.companion.identity}`);
        if (userData.companion.relation) compStr.push(`关系: ${userData.companion.relation}`);
        if (userData.companion.looks.length) compStr.push(`容貌: ${userData.companion.looks.join('、')}`);
        if (userData.companion.temperaments.length) compStr.push(`气质: ${userData.companion.temperaments.join('、')}`);
        if (userData.companion.talents.length) compStr.push(`才情: ${userData.companion.talents.join('、')}`);
        if (userData.companion.virtues.length) compStr.push(`品德: ${userData.companion.virtues.join('、')}`);
        if (userData.companion.custom_traits) compStr.push(`其他特质: ${userData.companion.custom_traits}`);
        lines.push(`相伴佳人: ${compStr.join(' | ')}`);

        const sexChoicesStr = Object.entries(userData.companion.sex_choices)
            .filter(([, choices]) => choices.length > 0)
            .map(([category, choices]) => `${category}: ${choices.join('、')}`)
            .join('；');
        if (sexChoicesStr) {
            lines.push(`房中私密: ${sexChoicesStr}`);
        }
    }

    if(userData.relations) lines.push(`人际关系: ${userData.relations}`);
    if(userData.force && userData.force.dynamic) lines.push(`势力动态: ${userData.force.dynamic}`);
    if(userData.custom) lines.push(`其他设定: ${userData.custom}`);
    return lines.join('\n');
}

