let userData = {
    name: '', zi: '', age: '',
    className: '',
    type: '', // 雅集宴会 或 纵情出游
    options: {} // 根据type存储选项
};

let currentPage = 0;
const totalPages = 6;

function goToPage(n) {
    document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
    document.getElementById('page-' + n)?.classList.add('active');
    currentPage = n;
    updateStepIndicator();
}

function updateStepIndicator() {
    const ind = document.getElementById('step-indicator');
    ind.innerHTML = '';
    for (let i = 0; i < totalPages; i++) {
        const d = document.createElement('div');
        d.className = 'step-dot';
        if (i === currentPage) d.classList.add('active');
        if (i < currentPage) d.classList.add('done');
        ind.appendChild(d);
    }
}

function selectCard(el, isMultiSelect = false) {
    if (isMultiSelect) {
        el.classList.toggle('selected');
    } else {
        const siblings = el.parentElement.querySelectorAll('.card, .sub-card');
        siblings.forEach(c => c.classList.remove('selected'));
        el.classList.add('selected');
    }
}

function renderCards(containerId, items, onSelect, isMultiSelect = false, cardClass = 'card') {
    const container = document.getElementById(containerId);
    container.innerHTML = '';
    items.forEach(item => {
        const card = document.createElement('div');
        card.className = cardClass;
        card.innerHTML = `<div class="card-title">${item.name}</div><div class="card-desc">${item.desc}</div>`;
        card.onclick = () => {
            selectCard(card, isMultiSelect);
            onSelect(item, card.classList.contains('selected'));
        };
        container.appendChild(card);
    });
}

function initPages() {
    renderCards('class-cards', data.classes, (item) => {
        userData.className = item.name;
    });

    renderCards('type-cards', data.types, (item) => {
        userData.type = item.name;
    });
}

function saveBasicInfo() {
    userData.name = document.getElementById('input-name').value.trim();
    userData.zi = document.getElementById('input-zi').value.trim();
    userData.age = document.getElementById('input-age').value.trim();
    if (!userData.name) { alert('请留下大名'); return; }
    goToPage(2);
}

function saveClass() {
    if (!userData.className) { alert('请选择门第出身'); return; }
    goToPage(3);
}

function saveType() {
    if (!userData.type) { alert('请选择雅集形式'); return; }

    // 初始化选项容器
    const container = document.getElementById('options-container');
    container.innerHTML = '';
    userData.options = {};

    const sourceData = userData.type === '雅集宴会' ? data.banquet : data.outing;

    document.getElementById('options-title').innerText = userData.type === '雅集宴会' ? '宴会布置' : '出游规划';
    document.getElementById('options-guide').innerText = userData.type === '雅集宴会' ? '丝竹之音，山水之乐。请挑选宴会的诸般风雅之事。(可多选)' : '策马扁舟，寻幽探险。请挑选出游的诸般逸事。(可多选)';

    for (const category in sourceData) {
        userData.options[category] = []; // 初始化空数组
        const section = document.createElement('div');
        section.className = 'sub-section';
        section.innerHTML = `<h3 class="sub-section-title">—— ${category} ——</h3><div id="options-${category}" class="sub-grid"></div>`;
        container.appendChild(section);

        renderCards(`options-${category}`, sourceData[category], (item, isSelected) => {
            const list = userData.options[category];
            if (isSelected) {
                if (!list.includes(item.name)) list.push(item.name);
            } else {
                const idx = list.indexOf(item.name);
                if (idx > -1) list.splice(idx, 1);
            }
        }, true, 'sub-card');
    }

    goToPage(4);
}

function saveOptions() {
    updateSummary();
    goToPage(5);
}

function updateSummary() {
    const container = document.getElementById('summary-info');
    let html = `<strong>名士：</strong>${userData.name}`;
    if (userData.zi) html += ` <strong>字</strong> ${userData.zi}`;
    if (userData.age) html += ` <strong>年方</strong> ${userData.age}`;
    html += `<br><strong>门第：</strong>${userData.className}<br><br>`;

    html += `<div style="text-align:center; border-bottom: 1px dashed var(--border); margin: 8px 0; color: var(--gold);">【 ${userData.type} 】</div>`;

    for (const cat in userData.options) {
        const items = userData.options[cat];
        html += `<strong>${cat}：</strong>${items.length > 0 ? items.join('、') : '随性而为'}<br>`;
    }

    container.innerHTML = html;
}

function formatOutput() {
    let lines = [];
    lines.push(`【魏晋风流·${userData.type}名帖】`);
    lines.push(`姓名: ${userData.name}`);
    if(userData.zi) lines.push(`表字: ${userData.zi}`);
    if(userData.age) lines.push(`年龄: ${userData.age}`);
    lines.push(`门第阶级: ${userData.className}`);
    lines.push(`\n【${userData.type}设定】`);
    for (const cat in userData.options) {
        const items = userData.options[cat];
        lines.push(`${cat}: ${items.length > 0 ? items.join('、') : '未定'}`);
    }

    if (userData.type === '雅集宴会') {
        lines.push(`\n请根据以上名帖与宴会设定，为我推演一场充满魏晋风度、名士风流的宴会场景。重点展现越名教而任自然的狂放、清谈论玄的机锋，或是服石饮酒后的癫狂放达。`);
    } else {
        lines.push(`\n请根据以上名帖与出游设定，为我推演一场充满魏晋风度、名士风流的纵情出游。重点展现寄情山水、超然物外的闲适，或是旅途之中放浪形骸、随性而至的野趣。`);
    }

    return lines.join('\n');
}

function showPreviewModal() {
    const modal = document.getElementById('preview-modal');
    const textarea = document.getElementById('preview-textarea');
    const copyBtn = document.getElementById('btn-copy');

    textarea.value = formatOutput();
    copyBtn.innerText = '誊写名帖';
    copyBtn.style.borderColor = 'var(--gold)';
    copyBtn.style.color = 'var(--gold-dark)';

    modal.classList.add('show');
}

function closePreviewModal() {
    document.getElementById('preview-modal').classList.remove('show');
}

function copyPreviewText() {
    const textarea = document.getElementById('preview-textarea');
    const copyBtn = document.getElementById('btn-copy');

    textarea.select();
    textarea.setSelectionRange(0, 99999);
    try {
        document.execCommand('copy');
        copyBtn.innerText = '已誊写！';
        copyBtn.style.borderColor = 'var(--text-muted)';
        copyBtn.style.color = 'var(--text-muted)';
    } catch (err) {
        console.error('复制失败', err);
    }
}

function onConfirm() {
    try {
        const charWB = getCharWorldbookNames('current');
        const wbName = charWB.primary;
        if (!wbName) {
            alert('当前角色卡未绑定主世界书，无法注入设定。请先绑定。');
            return;
        }
        deleteWorldbookEntries(wbName, (entry) => entry.name === '魏晋风流设定').then(() => {
            return createWorldbookEntries(wbName, [{
                name: '魏晋风流设定',
                enabled: true,
                strategy: { type: 'constant' },
                position: { type: 'before_character_definition' },
                content: formatOutput(),
            }]);
        }).then(() => {
            return createChatMessages([{ role: 'user', message: formatOutput() }]);
        }).then(() => {
            return triggerSlash('/send');
        }).catch((err) => {
            alert('操作失败: ' + (err.message || String(err)));
        });
    } catch(e) {
        console.log('Output:\n', formatOutput());
        alert('未在SillyTavern环境中运行，无法发送。设定已输出至控制台。\n' + e.message);
    }
}

document.addEventListener('DOMContentLoaded', () => {
    initPages();
    updateStepIndicator();
});
</script>
</body>
</html>
