    <div class="decree-container" id="content">
        <div style="text-align:center; color:#999; padding:20px;">正在加载文书...</div>
    </div>

    <script>
        /* 默认的示例数据，用于没有获取到真实AI输出时展示界面 */
        var defaultData = {
            '类型': '军事调令',
            '内容': '奉朝廷之命，查边关告急，特令尔等率【精锐三千】即日启程，驰援【潼关】。军情如火，【不得有误】！',
            '落款': '大司马 桓',
            '选项A': '称病不前',
            'A建议': '副将雷豹按着刀柄，粗声道：“将军，我军新败，粮草不济，此时出兵无异于送死，不如称病拖延。”',
            'A心理话': '若是去送死，我还不如早点带人跑路，这兵荒马乱的，保命要紧。',
            '选项B': '克日出师',
            'B建议': '长史柳文书拱手进言：“将军，军令如山，当点齐兵马，星夜兼程，以解国难。”',
            'B心理话': '朝廷虽然衰微，但大义名分仍在，此时抗旨必遭群起而攻之。',
            '选项C': '观望不前',
            'C建议': '偏将张老三抹了抹汗，附和道：“将军，不如先拔营行军，每日只走十里，看看各路诸侯的动静再说。”',
            'C心理话': '枪打出头鸟，谁爱去谁去，咱们在后面磨蹭着就行。',
            '选项D': '营啸哗变',
            'D建议': '中军帐外，斥候屯长跌跌撞撞地滚进来：“将军！不好了！将士们听说要去潼关送死，已经有几个营头闹起来了！”',
            'D心理话': '完了，彻底弹压不住了，弄不好将军的脑袋今晚就要搬家！'
        };

        function getMessageData() {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (!chatMessages || chatMessages.length === 0) {
                return null;
            }
            return chatMessages[0].message;
        }

        function parseData(messageText) {
            var result = {};
            var tagMatch = messageText.match(/<official_decree>([\s\S]*?)<\/official_decree>/);
            if (!tagMatch || !tagMatch[1]) return result;
            var content = tagMatch[1];

            var regex = /\[(.*?)\|(.*?)\]/g;
            var match;
            while ((match = regex.exec(content)) !== null) {
                result[match[1].trim()] = match[2].trim();
            }
            return result;
        }

        function getTypeClass(type) {
            if (!type) return 'zhengling';
            if (type.includes('旨')) return 'shengzhi';
            if (type.includes('军') || type.includes('调')) return 'junling';
            return 'zhengling';
        }

        /* 生成印章四个字的数组，以实现右起竖排的古印效果 */
        function getSealChars(type) {
            var text = '官府印信';
            if (type && type.includes('旨')) text = '受命于天';
            else if (type && (type.includes('军') || type.includes('调'))) text = '虎符印信';
            else if (type && type.includes('政')) text = '州郡大印';

            text = (text + '印信').substring(0, 4);
            return [text[2], text[0], text[3], text[1]];
        }

        function formatContent(text, typeClass) {
            if (!text) return '';
            return text.replace(/【(.*?)】/g, function(match, p1) {
                return `<span class="highlight-${typeClass}">${p1}</span>`;
            });
        }

        function renderPage(data) {
            var type = data['类型'] || '公文';
            var typeClass = getTypeClass(type);
            var rawContent = data['内容'] || '';
            var mainContent = formatContent(rawContent, typeClass);
            var signature = data['落款'] || '';

            var chars = getSealChars(type);
            var sealHtml = `
                <div>${chars[0]}</div><div>${chars[1]}</div>
                <div>${chars[2]}</div><div>${chars[3]}</div>
            `;

            document.getElementById('content').className = 'decree-container type-' + typeClass;

            var html = `
                <div class="header header-${typeClass}">${type}</div>
                <div class="content">${mainContent}</div>
                <div class="footer">
                    <div class="seal">${sealHtml}</div>
                    <div class="signature sig-${typeClass}">${signature}</div>
                </div>
                <div class="options-wrapper">
            `;

            var hasD = !!data['选项D'];
            var lockedIndex = hasD ? Math.floor(Math.random() * 3) : -1;

            var opts = [
                { key: 'A', tag: '抗拒' },
                { key: 'B', tag: '守正' },
                { key: 'C', tag: '随流' }
            ];

            opts.forEach(function(opt, index) {
                var titleKey = '选项' + opt.key;
                var adviceKey = opt.key + '建议';
                var thoughtKey = opt.key + '心理话';

                if (data[titleKey]) {
                    var isLocked = (index === lockedIndex);
                    var lockClass = isLocked ? 'locked' : '';
                    var clickEvent = isLocked ? '' : `onclick="handleClick('决断', '${data[titleKey]}')"`;

                    /* 去掉了前缀，直接渲染AI输出的内容 */
                    html += `
                        <div class="option-card ${lockClass}" ${clickEvent}>
                            <div class="locked-mask">变故横生 · 此策难行</div>
                            <div class="opt-title">【${opt.tag}】${data[titleKey]}</div>
                            <div class="opt-advice">${data[adviceKey] || ''}</div>
                            <div class="opt-thought">${data[thoughtKey] || ''}</div>
                        </div>
                    `;
                }
            });

            if (hasD) {
                html += `
                    <div class="option-card" style="border-color:#8b1d1d; background: rgba(139,29,29,0.05);" onclick="handleClick('应对惊变', '${data['选项D']}')">
                        <div class="opt-title" style="color:#8b1d1d;">【惊变】${data['选项D']}</div>
                        <div class="opt-advice" style="color:#5c1818;">${data['D建议'] || ''}</div>
                        <div class="opt-thought" style="color:#8b1d1d;">${data['D心理话'] || ''}</div>
                    </div>
                `;
            }

            html += `</div>`;
            document.getElementById('content').innerHTML = html;
        }

        function handleClick(keyword, param) {
            if (typeof triggerSlash === 'function') {
                triggerSlash('/send ' + keyword + '：' + param + '|/trigger');
            }
        }

        function init() {
            try {
                var messageText = getMessageData();
                var data = defaultData;

                if (messageText) {
                    var parsed = parseData(messageText);
                    if (parsed['类型'] || parsed['内容']) {
                        data = parsed;
                    }
                }

                renderPage(data);
            } catch (error) {
                console.error("解析错误:", error);
                renderPage(defaultData);
            }
        }

        $(function() { init(); });
    </script>
</body>
</html>
