      势力领袖: z.string().prefault(''),
      势力动态: z.string().prefault(''),
      部队: z.record(z.string().describe('部队名称'), z.object({
        类型: z.enum(['大营', '小营']).prefault('小营'),
        军属性质: z.enum(['私兵', '中央军', '驻内军', '边军']).prefault('私兵'),
        统帅: z.string().prefault(''),
        下辖小营: z.record(z.string().describe('小营名称'), z.object({
          兵种: z.string().prefault('步兵'),
          数量: z.coerce.number().prefault(0),
          统领: z.string().prefault(''),
          训练: z.enum(['乌合之众', '初经训练', '训练有素', '纪律严明', '精锐之师']).prefault('乌合之众'),
          士气: z.enum(['低落', '平稳', '高昂']).prefault('平稳'),
          装备: z.enum(['简陋', '标准', '精良']).prefault('简陋'),
          忠诚: z.enum(['叛乱', '摇摆', '忠诚']).prefault('忠诚'),
          补给: z.enum(['缺粮', '示警', '充足']).prefault('充足'),
        })).prefault({}),
        兵种: z.string().prefault('步兵'),
        统领: z.string().prefault(''),
        数量: z.coerce.number().prefault(0),
        训练: z.enum(['乌合之众', '初经训练', '训练有素', '纪律严明', '精锐之师']).prefault('乌合之众'),
        士气: z.enum(['低落', '平稳', '高昂']).prefault('平稳'),
        装备: z.enum(['简陋', '标准', '精良']).prefault('简陋'),
        忠诚: z.enum(['叛乱', '摇摆', '忠诚']).prefault('忠诚'),
        补给: z.enum(['缺粮', '示警', '充足']).prefault('充足'),
        评价: z.string().prefault(''),
        动向: z.string().prefault(''),
      })).prefault({}),
      部下: z.record(z.string().describe('部下姓名'), z.object({
        官职: z.string().prefault(''),
        好感: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(50),
        评价: z.string().prefault(''),
      })).prefault({}),
    }).prefault({}),

    子嗣: z.object({
        子嗣动态: z.string().prefault('家中尚无子嗣'),
        成员: z.record(z.string().describe('子嗣姓名'), z.object({
            年龄: z.coerce.number().prefault(0),
            身份: z.string().prefault(''),
            好感: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(50),
            评价: z.string().prefault(''),
        })).prefault({}),
    }).prefault({}),

    个人处境: z.object({
      当前危机: z.string().prefault(''),
      产业: z.record(z.string().describe('产业名称'), z.object({
        收入: z.string().describe('例如：500石 或 100金').prefault('0金'),
        支出: z.string().describe('例如：100石 或 20金').prefault('0金'),
        说明: z.string().describe('产业的情况说明或评价').prefault(''),
      })).catch({}).prefault({}),
      财政: z.object({
        储备: z.object({
          金钱: z.union([z.string(), z.number()]).transform(v => typeof v === 'number' ? `${v}金` : v).catch('0金').prefault('0金'),
          粮食: z.union([z.string(), z.number()]).transform(v => typeof v === 'number' ? `${v}石` : v).catch('0石').prefault('0石'),
        }).prefault({}),
        收支: z.string().prefault('勉强糊口'),
      }).prefault({}),
    }).prefault({}),

    功绩: z.record(z.string().describe('功绩ID'), z.object({
      类型: z.enum(['战绩', '政绩']).prefault('战绩'),
      描述: z.string().prefault(''),
      $time: z.coerce.number().prefault(() => Date.now()),
    })).prefault({}),

  }).prefault({}).transform(player => {
    // 称号计算的基础数据
    const titleTiers = {
      武力: [
        { min: 90, max: 100, title: '力能扛鼎' },
        { min: 75, max: 89, title: '勇冠三军' },
        { min: 50, max: 74, title: '膂力过人' },
        { min: 0, max: 49, title: '身壮体健' },
        { min: -50, max: -1, title: '体弱力薄' },
        { min: -75, max: -51, title: '力不能支' },
        { min: -100, max: -76, title: '弱不胜衣' }
      ],
      骑射: [
        { min: 90, max: 100, title: '辕门射戟' },
        { min: 75, max: 89, title: '百步穿杨' },
        { min: 50, max: 74, title: '弓马娴熟' },
        { min: 0, max: 49, title: '能骑会射' },
        { min: -50, max: -1, title: '弓马生疏' },
        { min: -75, max: -51, title: '射不穿札' },
        { min: -100, max: -76, title: '挽弓失弦' }
      ],
      统率: [
        { min: 90, max: 100, title: '天生将才' },
        { min: 75, max: 89, title: '指挥若定' },
        { min: 50, max: 74, title: '领兵之才' },
        { min: 0, max: 49, title: '可领什伍' },
        { min: -50, max: -1, title: '统军无方' },
        { min: -75, max: -51, title: '号令不明' },
        { min: -100, max: -76, title: '将不知兵' }
      ],
      政务: [
        { min: 90, max: 100, title: '经世之才' },
        { min: 75, max: 89, title: '治理之才' },
        { min: 50, max: 74, title: '通晓庶务' },
        { min: 0, max: 49, title: '初识吏事' },
        { min: -50, max: -1, title: '不谙吏事' },
        { min: -75, max: -51, title: '政务废弛' },
        { min: -100, max: -76, title: '错判刑名' }
      ],
      才学: [
        { min: 90, max: 100, title: '学富五车' },
        { min: 75, max: 89, title: '才高八斗' },
        { min: 50, max: 74, title: '文采斐然' },
        { min: 0, max: 49, title: '粗通文墨' },
        { min: -50, max: -1, title: '学识浅薄' },
        { min: -75, max: -51, title: '不通文墨' },
        { min: -100, max: -76, title: '胸无点墨' }
      ],
      魅力: [
        { min: 90, max: 100, title: '倾国倾城' },
        { min: 75, max: 89, title: '风姿特秀' },
        { min: 50, max: 74, title: '一表人才' },
        { min: 0, max: 49, title: '相貌平平' },
        { min: -50, max: -1, title: '其貌不扬' },
        { min: -75, max: -51, title: '面目可憎' },
        { min: -100, max: -76, title: '獐头鼠目' }
      ]
    };

    const baseTitles = new Set();
    for (const attrName in titleTiers) {
      for (const tier of titleTiers[attrName]) {
        baseTitles.add(tier.title);
      }
    }

    let uniqueTitles = {};
    for (const titleName in player.称号) {
      if (!baseTitles.has(titleName)) {
        uniqueTitles[titleName] = player.称号[titleName];
      }
    }

    uniqueTitles = _(uniqueTitles)
      .entries()
      .takeRight(10)
      .fromPairs()
      .value();

    player.称号 = { ...uniqueTitles };

    const getTier = (val) => {
      if (val >= 90) return 3;
      if (val >= 75) return 2;
      if (val >= 50) return 1;
      if (val >= 0) return 0;
      if (val >= -50) return -1;
      if (val >= -75) return -2;
      return -3;
    };

    const tiers = [];

    for (const attrName in titleTiers) {
      const currentAttrValue = player.属性[attrName];
      tiers.push(getTier(currentAttrValue));

      const matchedTiers = titleTiers[attrName];
      for (const tier of matchedTiers) {
        if (currentAttrValue >= tier.min && currentAttrValue <= tier.max) {
          player.称号[tier.title] = `因${attrName}属性处于 ${tier.min} 至 ${tier.max} 区间获得`;
          break;
        }
      }
    }

    const maxTier = Math.max(...tiers);
    const minTier = Math.min(...tiers);
    let talentLevel = '无';

    if (maxTier >= 1 && minTier <= -1) {
        const absMax = Math.max(maxTier, Math.abs(minTier));
        if (absMax === 3) talentLevel = '难言是非';
        else if (absMax === 2) talentLevel = '福祸相依';
        else talentLevel = '甘苦交织';
    }
    else if (maxTier >= 1 && minTier >= 0) {
        if (maxTier >= 3 && minTier >= 2) talentLevel = '天命所归';
        else if (maxTier >= 2 && minTier >= 1) talentLevel = '天纵之才';
        else if (maxTier >= 1 && minTier >= 0) talentLevel = '天赋异禀';
    }
    else if (minTier <= -1 && maxTier <= 0) {
        if (minTier <= -3 && maxTier <= -2) talentLevel = '命途多舛';
        else if (minTier <= -2 && maxTier <= -1) talentLevel = '弃如敞覆';
        else if (minTier <= -1 && maxTier <= 0) talentLevel = '愚钝之质';
    }

    player.身份信息.天赋级别 = talentLevel;

    if (player.势力信息.势力类型 === '暂无班底') {
      player.势力信息.势力名称 = '';
      player.势力信息.势力领袖 = '';
    }

    const currentPrestige = player.社会信息.声望;
    const isTopPrestige = ['名垂青史', '小儿止啼'].includes(currentPrestige);
    const isHighPrestige = ['威震天下', '恶名昭彰'].includes(currentPrestige);

    if (player.政治地位.称帝 && (!player.政治地位.称公 || !player.政治地位.称王)) {
      if (isTopPrestige) {
        player.政治地位.称公 = true;
        player.政治地位.称王 = true;
      } else if (isHighPrestige) {
        player.政治地位.称公 = true;
        player.政治地位.称王 = true;
        player.社会信息.声望 = currentPrestige === '威震天下' ? '名动一方' : '声名狼藉';
        player.社会信息.声望动态 = '因强行僭越，根基不稳，天下侧目，声望有所折损。';
      } else {
        player.政治地位.称帝 = false;
      }
    }

    if (player.政治地位.称王 && !player.政治地位.称公) {
      if (isTopPrestige) {
        player.政治地位.称公 = true;
      } else if (isHighPrestige) {
        player.政治地位.称公 = true;
        player.社会信息.声望 = currentPrestige === '威震天下' ? '名动一方' : '声名狼藉';
        player.社会信息.声望动态 = '因强行僭越，根基不稳，天下侧目，声望有所折损。';
      } else {
        player.政治地位.称王 = false;
      }
    }

    // 自动计算收支评价
    let netGold = 0;
    let netGrain = 0;

    _.forEach(player.个人处境.产业, (industry) => {
      const incMatch = String(industry.收入).match(/(-?\d+)(金|石)/);
      const expMatch = String(industry.支出).match(/(-?\d+)(金|石)/);

      if (incMatch) {
        const val = parseInt(incMatch[1], 10);
        if (incMatch[2] === '金') netGold += val;
        else if (incMatch[2] === '石') netGrain += val;
      }

      if (expMatch) {
        const val = parseInt(expMatch[1], 10);
        if (expMatch[2] === '金') netGold -= val;
        else if (expMatch[2] === '石') netGrain -= val;
      }
    });

    // 粗略按 1金 = 100石 换算总净收益，用于评定收支状况
    const totalNetValue = netGold * 100 + netGrain;

    if (totalNetValue < -5000) {
      player.个人处境.财政.收支 = '入不敷出';
    } else if (totalNetValue < 0) {
      player.个人处境.财政.收支 = '捉襟见肘';
    } else if (totalNetValue === 0) {
      player.个人处境.财政.收支 = '勉强糊口';
    } else if (totalNetValue < 10000) {
      player.个人处境.财政.收支 = '收支平衡';
    } else if (totalNetValue < 50000) {
      player.个人处境.财政.收支 = '日渐丰盈';
    } else {
      player.个人处境.财政.收支 = '财源滚滚';
    }

    const orderXunlian = ['乌合之众', '初经训练', '训练有素', '纪律严明', '精锐之师'];
    const orderShiqi = ['低落', '平稳', '高昂'];
    const orderZhuangbei = ['简陋', '标准', '精良'];
    const orderZhongcheng = ['叛乱', '摇摆', '忠诚'];
    const orderBuji = ['缺粮', '示警', '充足'];

    const getCalculatedState = (arr, orderArr, defaultVal) => {
      if (arr.length === 0) return defaultVal;
      const counts = _.countBy(arr);
      const maxCount = Math.max(...Object.values(counts));
      const topCandidates = Object.keys(counts).filter(k => counts[k] === maxCount);

      if (topCandidates.length === 1) {
        return topCandidates[0];
      } else {
        let sum = 0;
        let validCount = 0;
        arr.forEach(item => {
          const idx = orderArr.indexOf(item);
          if (idx !== -1) {
            sum += idx;
            validCount++;
          }
        });
        if (validCount === 0) return defaultVal;
        const avgIdx = Math.round(sum / validCount);
        return orderArr[avgIdx];
      }
    };

    _.forEach(player.势力信息.部队, (camp, name) => {
      if (camp.类型 === '小营') {
        if (camp.数量 >= 500) {
          camp.类型 = '大营';
          camp.统帅 = camp.统领 || '';
          camp.下辖小营 = {
            [`${name}本部`]: {
              兵种: camp.兵种 || '步兵',
              数量: camp.数量,
              统领: camp.统领 || '',
              训练: camp.训练 || '乌合之众',
              士气: camp.士气 || '平稳',
              装备: camp.装备 || '简陋',
              忠诚: camp.忠诚 || '忠诚',
              补给: camp.补给 || '充足'
            }
          };
          camp.兵种 = '';
          camp.统领 = '';
        }
      }

      if (camp.类型 === '大营') {
        let totalCount = 0;
        let xunlianArr = [];
        let shiqiArr = [];
        let zhuangbeiArr = [];
        let zhongchengArr = [];
        let bujiArr = [];

        _.forEach(camp.下辖小营, (subCamp) => {
          totalCount += subCamp.数量;
          xunlianArr.push(subCamp.训练);
          shiqiArr.push(subCamp.士气);
          zhuangbeiArr.push(subCamp.装备);
          zhongchengArr.push(subCamp.忠诚);
          bujiArr.push(subCamp.补给);
        });

        camp.数量 = totalCount;
        camp.训练 = getCalculatedState(xunlianArr, orderXunlian, '乌合之众');
        camp.士气 = getCalculatedState(shiqiArr, orderShiqi, '平稳');
        camp.装备 = getCalculatedState(zhuangbeiArr, orderZhuangbei, '简陋');
        camp.忠诚 = getCalculatedState(zhongchengArr, orderZhongcheng, '忠诚');
        camp.补给 = getCalculatedState(bujiArr, orderBuji, '充足');
      }
    });

    return player;
  }),

  佳人: z.object({
    后宫: z.record(z.string().describe('佳人姓名'), CompanionProfileSchema).prefault({}),
    佳人动向: z.string().prefault('后宫波澜不惊，各自安好。'),
  }).prefault({}),
});

$(() => {
  registerMvuSchema(schema);
})
